import{_ as t,o as d,c as e,a4 as a}from"./chunks/framework.BMymQDdR.js";const g=JSON.parse('{"title":"对象检查器","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Object-Inspector.md","filePath":"zh/v3/designer/Object-Inspector.md","lastUpdated":1780630099000}'),r={name:"v3/designer/Object-Inspector.md"},o=a('<h1 id="对象检查器" tabindex="-1">对象检查器 <a class="header-anchor" href="#对象检查器" aria-label="Permalink to &quot;对象检查器&quot;">​</a></h1><p>对象检查器位于设计器右侧，用于查看和编辑选中组件的 <strong>属性</strong> 和 <strong>事件</strong>。当在设计画布或项目管理器中选中组件时，对象检查器自动同步显示该组件的信息。</p><h2 id="界面组成" tabindex="-1">界面组成 <a class="header-anchor" href="#界面组成" aria-label="Permalink to &quot;界面组成&quot;">​</a></h2><p>对象检查器由以下部分组成：</p><ul><li><strong>搜索框</strong> - 顶部搜索框，支持按属性名过滤</li><li><strong>标签页</strong> - 两个标签页：<strong>属性</strong> 和 <strong>事件</strong></li><li><strong>文档区</strong> - 底部预留的属性文档提示区域（开发中）</li></ul><h2 id="属性编辑" tabindex="-1">属性编辑 <a class="header-anchor" href="#属性编辑" aria-label="Permalink to &quot;属性编辑&quot;">​</a></h2><h3 id="属性列表" tabindex="-1">属性列表 <a class="header-anchor" href="#属性列表" aria-label="Permalink to &quot;属性列表&quot;">​</a></h3><p>属性列表以表格形式显示，包含两列：</p><table tabindex="0"><thead><tr><th>列</th><th>说明</th></tr></thead><tbody><tr><td>Name</td><td>属性名称</td></tr><tr><td>Value</td><td>属性当前值，可点击编辑</td></tr></tbody></table><h3 id="属性编辑方式" tabindex="-1">属性编辑方式 <a class="header-anchor" href="#属性编辑方式" aria-label="Permalink to &quot;属性编辑方式&quot;">​</a></h3><p>不同类型的属性使用不同的编辑器：</p><table tabindex="0"><thead><tr><th>属性类型</th><th>编辑方式</th><th>说明</th></tr></thead><tbody><tr><td>文本 (Text)</td><td>文本输入框</td><td>直接输入文本值</td></tr><tr><td>整数 (Int)</td><td>数字输入框</td><td>输入整数值</td></tr><tr><td>浮点数 (Float)</td><td>数字输入框</td><td>输入浮点数值</td></tr><tr><td>布尔 (CheckBox)</td><td>复选框</td><td>勾选/取消勾选</td></tr><tr><td>枚举 (ComboBox)</td><td>下拉框</td><td>从预定义选项中选择</td></tr><tr><td>集合 (Set)</td><td>复选列表</td><td>多选设置集合值</td></tr><tr><td>颜色 (Color)</td><td>颜色选择器</td><td>弹出颜色选择对话框</td></tr><tr><td>类实例 (Class)</td><td>特殊处理</td><td>如 Icon 属性弹出图标编辑器</td></tr><tr><td>事件 (Method)</td><td>下拉框</td><td>选择或输入事件处理函数名</td></tr><tr><td>字符 (Uint16)</td><td>文本输入框</td><td>输入单字符或多字符串</td></tr></tbody></table><h3 id="修改属性值" tabindex="-1">修改属性值 <a class="header-anchor" href="#修改属性值" aria-label="Permalink to &quot;修改属性值&quot;">​</a></h3><ol><li>在属性列表中 <strong>单击</strong> 要修改的属性值列</li><li>根据属性类型出现对应的编辑器</li><li>输入或选择新值</li><li>按 <code>Enter</code> 或点击其他位置确认修改</li></ol><h3 id="属性修改效果" tabindex="-1">属性修改效果 <a class="header-anchor" href="#属性修改效果" aria-label="Permalink to &quot;属性修改效果&quot;">​</a></h3><p>属性修改后：</p><ul><li>设计画布上的组件 <strong>实时更新</strong> 显示效果</li><li>UI 布局文件自动同步更新</li><li>已修改的属性值以 <strong>蓝色</strong> 高亮显示</li><li>颜色属性的值以对应 <strong>颜色</strong> 显示</li></ul><h3 id="属性分组" tabindex="-1">属性分组 <a class="header-anchor" href="#属性分组" aria-label="Permalink to &quot;属性分组&quot;">​</a></h3><p>某些组件的属性按子对象分组显示，如 <code>Font.Size</code>、<code>Font.Style</code> 等。展开分组可查看和编辑子属性。</p><h2 id="事件绑定" tabindex="-1">事件绑定 <a class="header-anchor" href="#事件绑定" aria-label="Permalink to &quot;事件绑定&quot;">​</a></h2><h3 id="事件列表" tabindex="-1">事件列表 <a class="header-anchor" href="#事件列表" aria-label="Permalink to &quot;事件列表&quot;">​</a></h3><p>事件列表同样以表格形式显示：</p><table tabindex="0"><thead><tr><th>列</th><th>说明</th></tr></thead><tbody><tr><td>Name</td><td>事件名称（如 OnClick、OnChange 等）</td></tr><tr><td>Value</td><td>事件处理函数名，下拉框选择或手动输入</td></tr></tbody></table><h3 id="绑定事件" tabindex="-1">绑定事件 <a class="header-anchor" href="#绑定事件" aria-label="Permalink to &quot;绑定事件&quot;">​</a></h3><ol><li>切换到 <strong>事件</strong> 标签页</li><li>找到要绑定的事件（如 <code>OnClick</code>）</li><li><strong>单击</strong> Value 列，出现下拉框</li><li>从下拉框中选择已有函数，或手动输入新的函数名</li><li>按 <code>Enter</code> 确认</li></ol><h3 id="事件代码生成" tabindex="-1">事件代码生成 <a class="header-anchor" href="#事件代码生成" aria-label="Permalink to &quot;事件代码生成&quot;">​</a></h3><p>绑定事件后，设计器自动：</p><ol><li>在用户的 <code>.go</code> 文件中生成对应的事件处理函数</li><li>函数签名符合 ENERGY 框架规范</li><li>使用 AST 技术保护用户已编写的代码不被覆盖</li></ol><h3 id="支持的常见事件" tabindex="-1">支持的常见事件 <a class="header-anchor" href="#支持的常见事件" aria-label="Permalink to &quot;支持的常见事件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>事件名</th><th>触发时机</th></tr></thead><tbody><tr><td>OnClick</td><td>鼠标单击</td></tr><tr><td>OnDblClick</td><td>鼠标双击</td></tr><tr><td>OnMouseDown</td><td>鼠标按下</td></tr><tr><td>OnMouseUp</td><td>鼠标抬起</td></tr><tr><td>OnMouseMove</td><td>鼠标移动</td></tr><tr><td>OnChange</td><td>值改变</td></tr><tr><td>OnKeyPress</td><td>按键按下</td></tr><tr><td>OnKeyDown</td><td>键盘按下</td></tr><tr><td>OnKeyUp</td><td>键盘抬起</td></tr><tr><td>OnEnter</td><td>获得焦点</td></tr><tr><td>OnExit</td><td>失去焦点</td></tr><tr><td>OnResize</td><td>大小改变</td></tr><tr><td>OnShow</td><td>窗体显示</td></tr><tr><td>OnClose</td><td>窗体关闭</td></tr></tbody></table><h2 id="属性与-go-代码的关系" tabindex="-1">属性与 Go 代码的关系 <a class="header-anchor" href="#属性与-go-代码的关系" aria-label="Permalink to &quot;属性与 Go 代码的关系&quot;">​</a></h2><p>对象检查器中修改的属性值会自动生成到 Go 代码中。生成规则：</p><ul><li>属性修改生成 <code>Set{属性名}(值)</code> 调用</li><li>例如：<code>Caption = &quot;Hello&quot;</code> → <code>m.SetCaption(&quot;Hello&quot;)</code></li><li>枚举类型使用 <code>lclTypes.</code> 前缀</li><li>集合类型使用 <code>lclTypes.NewSet(...)</code> 形式</li></ul><h2 id="属性同步" tabindex="-1">属性同步 <a class="header-anchor" href="#属性同步" aria-label="Permalink to &quot;属性同步&quot;">​</a></h2><p>以下操作会触发属性列表同步更新：</p><ul><li>在设计画布上选中不同组件</li><li>在项目管理器中点击组件树节点</li><li>切换设计窗体标签页</li><li>组件拖拽或调整大小后</li></ul>',36),l=[o];function i(n,h,s,c,b,u){return d(),e("div",null,l)}const q=t(r,[["render",i]]);export{g as __pageData,q as default};
